mapper.select:
SELECT r.test_id AS testId, r.student_username AS studentUsername, u.full_name AS fullName, t.test_name AS testName, r.score, r.percentile, r.rank, r.submitted_at AS submittedAt FROM results r JOIN users u ON r.student_username = u.username JOIN tests t ON r.test_id = t.test_id
AND r.test_id = #{testId}
AND r.student_username = #{studentUsername}
ORDER BY r.submitted_at DESC
